import React, { useState, useEffect } from 'react';
import { fetchCurrentUser, loginUser, signupUser, fetchRaceHistory, addFundsToWallet } from '../utils/typingApi';
import '../styles/TypeProfile.css';

export default function TypeProfile() {
  const [currentUser, setCurrentUser] = useState(null);
  const [showAuthForm, setShowAuthForm] = useState(false);
  const [authMode, setAuthMode] = useState('login');
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    username: '',
    phoneNumber: '',
  });
  const [raceHistory, setRaceHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [topUpAmount, setTopUpAmount] = useState('');
  const [topUpPhone, setTopUpPhone] = useState('');
  const [walletNotice, setWalletNotice] = useState('');

  useEffect(() => {
    const loadUser = async () => {
      const user = await fetchCurrentUser();
      setCurrentUser(user);
      if (user?.id) {
        const history = await fetchRaceHistory(user.id);
        setRaceHistory(history);
      }
      setLoading(false);
    };
    loadUser();
  }, []);

  useEffect(() => {
    if (currentUser?.phoneNumber) {
      setTopUpPhone(currentUser.phoneNumber);
    }
  }, [currentUser]);

  const handleAuthSubmit = async (e) => {
    e.preventDefault();
    try {
      let user;
      if (authMode === 'login') {
        user = await loginUser(formData.email, formData.password);
      } else {
        user = await signupUser(formData.username, formData.email, formData.password, formData.phoneNumber);
      }
      setCurrentUser(user);
      setShowAuthForm(false);
      setFormData({ email: '', password: '', username: '', phoneNumber: '' });
      setShowPassword(false);
    } catch (error) {
      console.error('Auth error:', error);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSignOut = () => {
    setCurrentUser(null);
    localStorage.removeItem('typearena_user');
  };

  const handleAddFunds = async (e) => {
    e.preventDefault();
    try {
      const result = await addFundsToWallet(topUpAmount, topUpPhone);
      if (result?.user) {
        setCurrentUser(result.user);
      }
      setWalletNotice(result?.message || 'Top-up request sent.');
      setTopUpAmount('');
    } catch (error) {
      setWalletNotice(error.message || 'Failed to add funds.');
    }
  };

  if (loading) {
    return <div className="profile-container"><p>Loading profile...</p></div>;
  }

  if (!currentUser) {
    return (
      <div className="profile-container">
        <div className="auth-section">
          <h1>Welcome to TypeArena</h1>
          {!showAuthForm ? (
            <div className="auth-buttons">
              <button
                className="btn btn-primary btn-lg"
                onClick={() => {
                  setAuthMode('login');
                  setShowAuthForm(true);
                }}
              >
                Sign In
              </button>
              <button
                className="btn btn-secondary btn-lg"
                onClick={() => {
                  setAuthMode('signup');
                  setShowAuthForm(true);
                }}
              >
                Create Account
              </button>
            </div>
          ) : (
            <form className="auth-form" onSubmit={handleAuthSubmit}>
              <h2>{authMode === 'login' ? 'Sign In' : 'Create Account'}</h2>

              {authMode === 'signup' && (
                <>
                  <input
                    type="text"
                    name="username"
                    placeholder="Username"
                    value={formData.username}
                    onChange={handleInputChange}
                    required
                  />
                  <input
                    type="tel"
                    name="phoneNumber"
                    placeholder="Phone Number"
                    value={formData.phoneNumber}
                    onChange={handleInputChange}
                    required
                  />
                </>
              )}

              <input
                type="email"
                name="email"
                placeholder="Email"
                value={formData.email}
                onChange={handleInputChange}
                required
              />

              <input
                type={showPassword ? 'text' : 'password'}
                name="password"
                placeholder="Password"
                value={formData.password}
                onChange={handleInputChange}
                required
              />
              <button
                type="button"
                className="password-toggle"
                onClick={() => setShowPassword((prev) => !prev)}
              >
                {showPassword ? 'Hide Password' : 'Show Password'}
              </button>

              <button type="submit" className="btn btn-primary">
                {authMode === 'login' ? 'Sign In' : 'Sign Up'}
              </button>

              <button
                type="button"
                className="btn btn-link"
                onClick={() => {
                  setAuthMode(authMode === 'login' ? 'signup' : 'login');
                  setFormData({ email: '', password: '', username: '', phoneNumber: '' });
                }}
              >
                {authMode === 'login'
                  ? "Don't have an account? Sign up"
                  : 'Already have an account? Sign in'}
              </button>

              <button
                type="button"
                className="btn btn-secondary"
                onClick={() => setShowAuthForm(false)}
              >
                Back
              </button>
            </form>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="profile-container">
      <div className="profile-header">
        <h1>👤 My Profile</h1>
        <button className="btn btn-danger" onClick={handleSignOut}>
          Sign Out
        </button>
      </div>

      <div className="profile-grid">
        {/* User Stats */}
        <div className="profile-card stats-card">
          <h2>{currentUser.username}</h2>
          <p className="welcome-message">Welcome, {currentUser.username}</p>
          <p className="email">{currentUser.email}</p>
          {currentUser.phoneNumber && <p className="email">{currentUser.phoneNumber}</p>}

          <div className="stats-grid">
            <div className="stat-box">
              <label>WPM</label>
              <span className="stat-value">{currentUser.wpm}</span>
            </div>
            <div className="stat-box">
              <label>Accuracy</label>
              <span className="stat-value">{currentUser.accuracy.toFixed(1)}%</span>
            </div>
            <div className="stat-box">
              <label>Races</label>
              <span className="stat-value">{currentUser.totalRaces}</span>
            </div>
            <div className="stat-box">
              <label>Wins</label>
              <span className="stat-value">{currentUser.wins}</span>
            </div>
            <div className="stat-box">
              <label>Win Rate</label>
              <span className="stat-value">
                {currentUser.totalRaces === 0
                  ? '0%'
                  : ((currentUser.wins / currentUser.totalRaces) * 100).toFixed(1) + '%'}
              </span>
            </div>
            <div className="stat-box">
              <label>Balance</label>
              <span className="stat-value earnings">KES {currentUser.balance.toLocaleString()}</span>
            </div>
          </div>

          <form className="wallet-topup" onSubmit={handleAddFunds}>
            <h3>Add Money</h3>
            <p className="wallet-help">
              Top up your account here. Tournament entry fees will be deducted from this balance.
            </p>
            <div className="wallet-row">
              <input
                type="tel"
                value={topUpPhone}
                onChange={(e) => setTopUpPhone(e.target.value)}
                placeholder="M-Pesa Phone Number"
                required
              />
              <input
                type="number"
                min="1"
                step="1"
                value={topUpAmount}
                onChange={(e) => setTopUpAmount(e.target.value)}
                placeholder="Amount in KES"
                required
              />
              <button type="submit" className="btn btn-primary">
                Add Funds
              </button>
            </div>
            {walletNotice && <p className="wallet-notice">{walletNotice}</p>}
          </form>
        </div>

        {/* Recent Races */}
        <div className="profile-card races-card">
          <h3>📊 Recent Races</h3>
          {raceHistory.length === 0 ? (
            <p className="empty-message">No races yet. Go join a tournament!</p>
          ) : (
            <div className="race-list">
              {raceHistory.slice(0, 5).map(race => (
                <div key={race.id} className="race-item">
                  <div className="race-info">
                    <span className="race-wpm">{race.wpm} WPM</span>
                    <span className="race-accuracy">{race.accuracy}% Accuracy</span>
                  </div>
                  <div className="race-result">
                    <span className={`place place-${race.place}`}>
                      #{race.place}
                    </span>
                    <span className="earnings">+KES {race.earnings}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
